function parseDate(d: string): Date {
  const parts = d.split("/");
  if (parts.length !== 3) return new Date();
  const day = parseInt(parts[0]);
  let month = parseInt(parts[1]) - 1;
  const year = parseInt(parts[2]);
  if (month > 11) month = 0;
  return new Date(year, month, day);
}

